import React, { useState } from 'react';

const Contact = () => {
  const [form, setForm] = useState({ name: '', email: '', message: '' });
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);

  const validate = () => {
    const e = {};
    if (!form.name.trim()) e.name = 'Name is required.';
    if (!form.email.trim()) e.email = 'Email is required.';
    else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = 'Enter a valid email.';
    if (!form.message.trim()) e.message = 'Message cannot be empty.';
    return e;
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setErrors({ ...errors, [e.target.name]: '' });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) return setErrors(errs);
    setSubmitted(true);
  };

  const socialLinks = [
    { href: 'https://www.facebook.com/alihakim.dimacaling15', img: '/images/facebook-logo.png', alt: 'Facebook' },
    { href: 'https://github.com/amd-16', img: '/images/github-logo.png', alt: 'GitHub' },
    { href: 'https://mail.google.com/mail/', img: '/images/gmail-logo.png', alt: 'Gmail' },
  ];

  return (
    <footer
      id="Contact"
      className="text-center pt-12 pb-10 px-4"
      style={{
        background: 'linear-gradient(180deg, #0a0f2e 0%, #00052b 100%)',
        borderTop: '1px solid rgba(0,112,204,0.3)',
      }}
    >
      {/* TITLE */}
      <h5
        className="italic font-bold mb-6 text-sm tracking-widest"
        style={{
          color: '#7fc5e8',
          fontFamily: "'Orbitron', sans-serif",
          letterSpacing: '3px',
        }}
      >
        CONTACT ME
      </h5>

      {/* SOCIAL LINKS */}
      <div className="flex justify-center items-center gap-5 mt-2 mb-6">
        {/* PHONE */}
        <p
          style={{
            color: 'rgba(255,255,255,0.75)',
            fontFamily: "'Orbitron', sans-serif",
            letterSpacing: '1px',
          }}
        >
          +639090909
        </p>

        {/* ICONS (FIXED) */}
        {socialLinks.map(({ href, img, alt }) => (
          <a
            key={alt}
            href={href}
            target="_blank"
            rel="noreferrer"
            className="w-12 h-12 flex items-center justify-center transition-transform duration-300 hover:scale-110"
          >
            <img
              src={img}
              alt={alt}
              className="max-w-full max-h-full object-contain"
            />
          </a>
        ))}
      </div>

      {/* FORM */}
      <div className="max-w-md mx-auto text-left mt-6">
        {submitted ? (
          <p className="text-center font-semibold" style={{ color: '#7be8b4' }}>
            Thanks, {form.name}! Your message has been sent.
          </p>
        ) : (
          <form onSubmit={handleSubmit} className="flex flex-col gap-4">
            <div>
              <input
                type="text"
                name="name"
                placeholder="Your name"
                value={form.name}
                onChange={handleChange}
                className="w-full p-2 text-sm rounded bg-white/5 border border-white/20 text-white outline-none"
              />
              {errors.name && <p className="text-xs mt-1 text-red-400">{errors.name}</p>}
            </div>

            <div>
              <input
                type="text"
                name="email"
                placeholder="Your email"
                value={form.email}
                onChange={handleChange}
                className="w-full p-2 text-sm rounded bg-white/5 border border-white/20 text-white outline-none"
              />
              {errors.email && <p className="text-xs mt-1 text-red-400">{errors.email}</p>}
            </div>

            <div>
              <textarea
                name="message"
                placeholder="Your message"
                value={form.message}
                onChange={handleChange}
                rows={4}
                className="w-full p-2 text-sm rounded bg-white/5 border border-white/20 text-white outline-none resize-none"
              />
              {errors.message && <p className="text-xs mt-1 text-red-400">{errors.message}</p>}
            </div>

            <button
              type="submit"
              className="py-2 rounded text-sm font-bold transition hover:opacity-90"
              style={{
                background: 'linear-gradient(90deg, #003791, #0070cc)',
                color: '#fff',
                letterSpacing: '2px',
              }}
            >
              SEND
            </button>
          </form>
        )}
      </div>

      {/* TERMS */}
      <a
        href="https://www.unitedresponse.org.uk/privacy-policy/"
        target="_blank"
        rel="noopener noreferrer"
        className="block mt-6 text-xs hover:underline"
        style={{ color: 'rgba(255,255,255,0.4)' }}
      >
        Terms & Conditions and Privacy Policy
      </a>

      {/* COPYRIGHT */}
      <p className="text-xs mt-3" style={{ color: 'rgba(255,255,255,0.25)' }}>
        © {new Date().getFullYear()} ALIHAKIM M. DIMACALING
      </p>
    </footer>
  );
};

export default Contact;
